=\"console-actions\">\n          <button class=\"btn-toggle\" title=\"收起\" @click=\"toggleExpand\">\n            <i class=\"fa-solid fa-chevron-down\" />\n          </button>\n        </div>\n      </div>\n\n      <div class=\"console-body\">\n        <!-- 功能切换标签 -->\n        <div class=\"tab-bar\">\n          <button\n            class=\"tab-btn\"\n            :class=\"{ active: activeTab === 'imageGen' }\"\n            @click=\"activeTab = 'imageGen'\"\n          >\n            <i class=\"fa-solid fa-image\" />\n            生图测试\n          </button>\n          <button\n            class=\"tab-btn\"\n            :class=\"{ active: activeTab === 'parser' }\"\n            @click=\"activeTab = 'parser'\"\n          >\n            <i class=\"fa-solid fa-code\" />\n            消息解析\n          </button>\n        </div>\n\n        <!-- ========== 生图测试 ========== -->\n        <div v-if=\"activeTab === 'imageGen'\" class=\"tab-content\">\n          <!-- 图片类型选择 -->\n          <div class=\"form-row\">\n            <label class=\"form-label\">图片类型</label>\n            <div class=\"type-selector\">\n              <button\n                class=\"type-btn\"\n                :class=\"{ active: imageType === 'background' }\"\n                @click=\"imageType = 'background'\"\n              >\n                <i class=\"fa-solid fa-image\" />\n                背景 (BG)\n              </button>\n              <button\n                class=\"type-btn\"\n                :class=\"{ active: imageType === 'cg' }\"\n                @click=\"imageType = 'cg'\"\n              >\n                <i class=\"fa-solid fa-portrait\" />\n                CG\n              </button>\n            </div>\n          </div>\n\n          <!-- 标题输入 -->\n          <div class=\"form-row\">\n            <label class=\"form-label\">标题 (可选)</label>\n            <input\n              v-model=\"imageTitle\"\n              type=\"text\"\n              class=\"form-input\"\n              placeholder=\"如：教室黄昏、雨夜告白\"\n            />\n          </div>\n\n          <!-- 提示词输入 -->\n          <div class=\"form-row\">\n            <label class=\"form-label\">提示词</label>\n            <textarea\n              v-model=\"prompt\"\n              class=\"form-textarea\"\n              placeholder=\"输入英文提示词，如：sfw, 1girl, classroom, sunset, window light\"\n              rows=\"2\"\n            />\n          </div>\n\n          <!-- 操作按钮 -->\n          <div class=\"form-row actions\">\n            <button :disabled=\"!prompt.trim()\" class=\"btn-action btn-generate\" @click=\"handleGenerateOnly\">\n              <i class=\"fa-solid fa-magic\" />\n              仅生成\n            </button>\n            <button :disabled=\"!prompt.trim()\" class=\"btn-action btn-write\" @click=\"handleWriteAndGenerate\">\n              <i class=\"fa-solid fa-pen\" />\n              写入消息并生成\n            </button>\n            <button class=\"btn-action btn-clear\" @click=\"handleClear\">\n              <i class=\"fa-solid fa-trash\" />\n              清空\n            </button>\n            <button class=\"btn-action btn-retry\" @click=\"store.openRetryPanel()\">\n              <i class=\"fa-solid fa-rotate-right\" />\n              打开重试弹窗\n            </button>\n          </div>\n\n          <!-- 状态信息 -->\n          <div v-if=\"generating\" class=\"status-bar\">\n            <i class=\"fa-solid fa-spinner fa-spin\" />\n            <span>正在生成图片...</span>\n          </div>\n          <div v-else-if=\"lastResult\" class=\"status-bar success\">\n            <i class=\"fa-solid fa-check\" />\n            <span>生成完成 ✓</span>\n          </div>\n        </div>\n\n        <!-- ========== 消息解析测试 ========== -->\n        <div v-if=\"activeTab === 'parser'\" class=\"tab-content\">\n          <!-- 快速测试用例 -->\n          <div class=\"quick-tests\">\n            <span class=\"quick-tests-label\">快速测试：</span>\n            <button\n              v-for=\"test in quickTests\"\n              :key=\"test.id\"\n              class=\"quick-test-btn\"\n              :title=\"test.description\"\n              @click=\"runQuickTest(test)\"\n            >\n              {{ test.name }}\n            </button>\n          </div>\n\n          <!-- 测试输入 -->\n          <div class=\"form-row\">\n            <label class=\"form-label\">测试输入</label>\n            <textarea\n              v-model=\"parserInput\"\n              class=\"form-textarea parser-input\"\n              placeholder=\"输入要测试的消息文本，如：[[character||角色名：零||台词：你好]]\"\n              rows=\"4\"\n            />\n          </div>\n\n          <!-- 测试按钮 -->\n          <div class=\"form-row actions\">\n            <button class=\"btn-action btn-generate\" @click=\"runParserTest\">\n              <i class=\"fa-solid fa-play\" />\n              运行测试\n            </button>\n            <button class=\"btn-action btn-clear\" @click=\"clearParserResult\">\n              <i class=\"fa-solid fa-trash\" />\n              清空结果\n            </button>\n          </div>\n\n          <!-- 测试结果 -->\n          <div v-if=\"parserResults.length > 0\" class=\"parser-results\">\n            <div class=\"results-header\">\n              <i class=\"fa-solid fa-list-check\" />\n              <span>解析结果 ({{ parserResults.length }} 个块)</span>\n            </div>\n            <div\n              v-for=\"(result, index) in parserResults\"\n              :key=\"index\"\n              class=\"result-item\"\n              :class=\"{ 'result-error': result.error }\"\n            >\n              <div class=\"result-header\">\n                <span class=\"result-index\">#{{ index + 1 }}</span>\n                <span class=\"result-type\">{{ result.type || 'unknown' }}</span>\n                <span v-if=\"result.character\" class=\"result-character\">{{ result.character }}</span>\n              </div>\n              <div v-if=\"result.text\" class=\"result-text\">\n                <span class=\"result-field-label\">台词：</span>{{ result.text }}\n              </div>\n              <div v-if=\"result.message\" class=\"result-text\">\n                <span class=\"result-field-label\">旁白：</span>{{ result.message }}\n              </div>\n              <div v-if=\"result.scene\" class=\"result-field\">\n                <span class=\"result-field-label\">场景：</span>{{ result.scene }}\n              </div>\n              <div v-if=\"result.error\" class=\"result-error-text\">\n                <i class=\"fa-solid fa-exclamation-triangle\" />\n                {{ result.error }}\n              </div>\n            </div>\n          </div>\n\n          <!-- 裸文本测试结果 -->\n          <div v-if=\"plainTextResult !== null\" class=\"plain-text-result\">\n            <div class=\"results-header\">\n              <i class=\"fa-solid fa-font\" />\n              <span>剧情纯文本</span>\n            </div>\n            <pre class=\"plain-text-content\">{{ plainTextResult || '(空)' }}</pre>\n          </div>\n        </div>\n      </div>\n    </div>\n  </div>\n</template>\n\n<script setup lang=\"ts\">\nimport { useVNStore } from './store';\nimport { parseMessageBlocks, extractContentTag, extractPlainTextFromContent } from './utils/messageParser';\nimport type { MessageBlock } from './types/message';\n\nconst store = useVNStore();\n\nconst isCollapsed = ref(true);\nconst activeTab = ref<'imageGen' | 'parser'>('imageGen');\n\n// ========== 生图测试相关 ==========\n\nconst imageType = ref<'background' | 'cg'>('background');\nconst imageTitle = ref('');\nconst prompt = ref('');\nconst generating = ref(false);\nconst lastResult = ref(false);\n\nfunction toggleExpand() {\n  isCollapsed.value = true;\n}\n\nasync function handleWriteAndGenerate() {\n  if (!prompt.value.trim()) return;\n\n  generating.value = true;\n  lastResult.value = false;\n\n  const titleStr = imageTitle.value.trim() ? `\\ntitle###${imageTitle.value.trim()}###` : '';\n  const tagBlock = `<${imageType.value}>${titleStr}\\nimage###${prompt.value.trim()}###\\n</${imageType.value}>`;\n\n  try {\n    const context = (window as any).__streamingMessageContext;\n    if (context?.message_id) {\n      const messages = getChatMessages(context.message_id) as any[];\n      if (messages.length > 0) {\n        const updatedMessage = messages[0].message + '\\n' + tagBlock;\n        await setChatMessages([{ ...messages[0], message: updatedMessage }], messages[0].id as any);\n        console.info('[TestConsole] 已写入标签到消息:', tagBlock);\n      }\n    }\n\n    await new Promise(resolve => setTimeout(resolve, 100));\n\n    if (context?.message_id) {\n      await store.reparseImageTagsFromMessage(context.message_id);\n    } else if (imageType.value === 'background') {\n      store.requestBackgroundImage(prompt.value.trim(), imageTitle.value.trim() || undefined);\n    } else {\n      store.requestCgImage(prompt.value.trim(), imageTitle.value.trim() || undefined);\n    }\n\n    console.info('[TestConsole] 生图请求已发送');\n  } catch (e) {\n    console.error('[TestConsole] 流程执行失败:', e);\n  } finally {\n    setTimeout(() => {\n      generating.value = false;\n      lastResult.value = true;\n      setTimeout(() => {\n        lastResult.value = false;\n      }, 3000);\n    }, 1500);\n  }\n}\n\nasync function handleGenerateOnly() {\n  if (!prompt.value.trim()) return;\n\n  generating.value = true;\n  lastResult.value = false;\n\n  try {\n    if (imageType.value === 'background') {\n      store.requestBackgroundImage(prompt.value.trim(), imageTitle.value.trim() || undefined);\n    } else {\n      store.requestCgImage(prompt.value.trim(), imageTitle.value.trim() || undefined);\n    }\n    console.info('[TestConsole] 生图请求已发送');\n  } catch (e) {\n    console.error('[TestConsole] 生成失败:', e);\n  } finally {\n    setTimeout(() => {\n      generating.value = false;\n      lastResult.value = true;\n      setTimeout(() => {\n        lastResult.value = false;\n      }, 3000);\n    }, 1500);\n  }\n}\n\nfunction handleClear() {\n  imageTitle.value = '';\n  prompt.value = '';\n  imageType.value = 'background';\n}\n\n// ========== 消息解析测试相关 ==========\n\ninterface QuickTest {\n  id: string;\n  name: string;\n  description: string;\n  input: string;\n}\n\ninterface ParserResult {\n  type?: string;\n  character?: string;\n  text?: string;\n  message?: string;\n  scene?: string;\n  isCG?: boolean;\n  motion?: string;\n  expression?: string;\n  error?: string;\n}\n\nconst quickTests: QuickTest[] = [\n  {\n    id: 'char-basic',\n    name: '角色对话',\n    description: '测试基本角色对话块解析',\n    input: '<content>[[character||角色名：零||台词：你好世界]]</content>',\n  },\n  {\n    id: 'narration-basic',\n    name: '旁白',\n    description: '测试旁白块解析',\n    input: '<content>[[narration||旁白：夜幕降临]]</content>',\n  },\n  {\n    id: 'blacktext-basic',\n    name: '黑屏文字',\n    description: '测试黑屏文字块解析',\n    input: '<content>[[blacktext||黑屏文字：游戏开始]]</content>',\n  },\n  {\n    id: 'scene-inherit',\n    name: '场景继承',\n    description: '测试场景继承机制',\n    input:\n      '<content>[[narration||场景：第一幕||旁白：开始]]\\n[[character||角色名：零||台词：无场景继承]]\\n[[character||角色名：零||台词：还是无场景]]</content>',\n  },\n  {\n    id: 'multi-line',\n    name: '多行台词',\n    description: '测试 \\\\n 拆分的台词',\n    input: '<content>[[character||角色名：零||台词：第一句\\\\n第二句\\\\n第三句]]</content>',\n  },\n  {\n    id: 'cg-scene',\n    name: 'CG场景',\n    description: '测试 CG 场景指定',\n    input: '<content>[[character||角色名：零||CG场景：告白||台词：心跳加速]]</content>',\n  },\n  {\n    id: 'plain-text',\n    name: '裸文本',\n    description: '测试无格式的纯文本',\n    input: '<content>这是一段没有任何格式的纯文本旁白</content>',\n  },\n  {\n    id: 'empty-content',\n    name: '空标签',\n    description: '测试空的 content 标签',\n    input: '<content></content>',\n  },\n  {\n    id: 'no-content',\n    name: '无标签',\n    description: '测试完全没有 content 标签的文本',\n    input: '这是一个没有任何标签的纯文本',\n  },\n  {\n    id: 'mixed',\n    name: '混合内容',\n    description: '测试混合角色和旁白',\n    input:\n      '<content>旁白先行。\\n[[character||角色名：零||台词：我是零]]\\n[[narration||旁白：零说了话]]\\n[[character||角色名：哈||台词：我是哈]]\\n全部结束。</content>',\n  },\n];\n\nconst parserInput = ref('');\nconst parserResults = ref<ParserResult[]>([]);\nconst plainTextResult = ref<string | null>(null);\n\nasync function runQuickTest(test: QuickTest) {\n  parserInput.value = test.input;\n  await runParserTest();\n}\n\nasync function runParserTest() {\n  if (!parserInput.value.trim()) {\n    store.showToast('请输入测试内容');\n    return;\n  }\n\n  parserResults.value = [];\n  plainTextResult.value = null;\n\n  try {\n    // 1. 测试 extractContentTag\n    const contentTag = extractContentTag(parserInput.value);\n    console.info('[TestConsole] extractContentTag 结果:', contentTag ? `\"${contentTag.substring(0, 50)}...\"` : '(空)');\n\n    // 2. 测试 extractPlainTextFromContent\n    plainTextResult.value = extractPlainTextFromContent(parserInput.value);\n    console.info('[TestConsole] extractPlainTextFromContent 结果:', plainTextResult.value);\n\n    // 3. 测试 parseMessageBlocks 并直接渲染到 VN 舞台\n    const blocks = await parseMessageBlocks(parserInput.value);\n    console.info('[TestConsole] parseMessageBlocks 结果:', blocks);\n\n    // 4. 将解析结果直接设置到 store，渲染到 VN 舞台\n    store.currentMessageBlocks.splice(0, store.currentMessageBlocks.length, ...blocks);\n    store.currentDialogueIndex = 0;\n    console.info('[TestConsole] 已渲染到 VN 舞台，共', blocks.length, '个块');\n\n    // 5. 转换结果用于显示\n    parserResults.value = blocks.map((block: MessageBlock) => ({\n      type: block.type,\n      character: block.character,\n      text: block.text,\n      message: block.message,\n      scene: block.scene,\n      isCG: block.isCG,\n      motion: block.motion,\n      expression: block.expression,\n    }));\n\n    if (blocks.length === 0) {\n      // 检查是否有 content 标签但解析失败\n      if (contentTag !== '') {\n        parserResults.value.push({\n          error: '未识别到任何 [[...]] 格式块（纯文本已通过 extractPlainTextFromContent 提取）',\n        });\n      } else {\n        parserResults.value.push({\n          error: '消息中没有 <content> 标签',\n        });\n      }\n    }\n\n    store.showToast(`解析完成：${blocks.length} 个块，已渲染到舞台`);\n  } catch (e: any) {\n    console.error('[TestConsole] 解析失败:', e);\n    parserResults.value = [\n      {\n        error: `解析错误: ${e.message || e}`,\n      },\n    ];\n    store.showToast('解析失败');\n  }\n}\n\nfunction clearParserResult() {\n  parserInput.value = '';\n  parserResults.value = [];\n  plainTextResult.value = null;\n}\n</script>\n\n<style scoped>\n.test-console {\n  position: fixed;\n  bottom: 0;\n  left: 0;\n  right: 0;\n  z-index: 100;\n  font-family: 'Consolas', 'Monaco', monospace;\n}\n\n/* 收起状态 */\n.console-trigger {\n  display: flex;\n  align-items: center;\n  gap: 8px;\n  padding: 6px 16px;\n  background: rgba(42, 36, 32, 0.95);\n  border-top: 2px solid var(--rust);\n  color: rgba(212, 197, 160, 0.8);\n  font-size: 12px;\n  cursor: pointer;\n  transition: all 0.2s ease;\n  width: fit-content;\n}\n\n.console-trigger:hover {\n  background: rgba(139, 69, 19, 0.3);\n  color: rgba(212, 197, 160, 1);\n}\n\n/* 展开状态 */\n.console-panel {\n  background: rgba(30, 26, 22, 0.98);\n  border-top: 2px solid var(--rust);\n  box-shadow: 0 -4px 20px rgba(0, 0, 0, 0.5);\n}\n\n.console-header {\n  display: flex;\n  align-items: center;\n  justify-content: space-between;\n  padding: 8px 12px;\n  background: rgba(42, 36, 32, 0.8);\n  border-bottom: 1px solid rgba(139, 69, 19, 0.3);\n}\n\n.console-title {\n  display: flex;\n  align-items: center;\n  gap: 8px;\n  color: rgba(212, 197, 160, 0.9);\n  font-size: 12px;\n  font-weight: bold;\n}\n\n.console-actions {\n  display: flex;\n  gap: 8px;\n}\n\n.btn-toggle {\n  background: none;\n  border: none;\n  color: rgba(212, 197, 160, 0.6);\n  cursor: pointer;\n  padding: 4px 8px;\n  font-size: 12px;\n  transition: color 0.2s;\n}\n\n.btn-toggle:hover {\n  color: rgba(212, 197, 160, 1);\n}\n\n.console-body {\n  padding: 12px;\n  max-height: 400px;\n  overflow-y: auto;\n}\n\n.tab-content {\n  margin-top: 12px;\n}\n\n/* 标签切换 */\n.tab-bar {\n  display: flex;\n  gap: 4px;\n  border-bottom: 1px solid rgba(139, 69, 19, 0.3);\n  padding-bottom: 8px;\n}\n\n.tab-btn {\n  display: flex;\n  align-items: center;\n  gap: 6px;\n  padding: 6px 14px;\n  background: rgba(20, 18, 15, 0.6);\n  border: 1px solid rgba(139, 69, 19, 0.3);\n  border-radius: 4px 4px 0 0;\n  color: rgba(212, 197, 160, 0.5);\n  font-family: inherit;\n  font-size: 11px;\n  cursor: pointer;\n  transition: all 0.2s;\n}\n\n.tab-btn:hover {\n  background: rgba(139, 69, 19, 0.2);\n  color: rgba(212, 197, 160, 0.7);\n}\n\n.tab-btn.active {\n  background: rgba(139, 69, 19, 0.3);\n  border-color: var(--rust);\n  border-bottom-color: rgba(30, 26, 22, 0.98);\n  color: rgba(212, 197, 160, 1);\n  margin-bottom: -1px;\n  padding-bottom: 7px;\n}\n\n.form-row {\n  display: flex;\n  align-items: center;\n  gap: 12px;\n  margin-bottom: 10px;\n}\n\n.form-row.actions {\n  justify-content: flex-start;\n  gap: 8px;\n  margin-top: 12px;\n}\n\n.form-label {\n  min-width: 70px;\n  color: rgba(139, 69, 19, 0.9);\n  font-size: 11px;\n  text-transform: uppercase;\n  letter-spacing: 0.5px;\n}\n\n.form-input,\n.form-textarea {\n  flex: 1;\n  background: rgba(20, 18, 15, 0.8);\n  border: 1px solid rgba(139, 69, 19, 0.4);\n  border-radius: 4px;\n  padding: 6px 10px;\n  color: rgba(212, 197, 160, 0.9);\n  font-family: inherit;\n  font-size: 12px;\n  outline: none;\n  transition: border-color 0.2s;\n}\n\n.form-input:focus,\n.form-textarea:focus {\n  border-color: var(--rust);\n}\n\n.form-input::placeholder,\n.form-textarea::placeholder {\n  color: rgba(212, 197, 160, 0.3);\n}\n\n.form-textarea {\n  resize: vertical;\n  min-height: 50px;\n}\n\n.parser-input {\n  min-height: 80px;\n}\n\n/* 类型选择器 */\n.type-selector {\n  display: flex;\n  gap: 8px;\n}\n\n.type-btn {\n  display: flex;\n  align-items: center;\n  gap: 6px;\n  padding: 6px 12px;\n  background: rgba(20, 18, 15, 0.8);\n  border: 1px solid rgba(139, 69, 19, 0.4);\n  border-radius: 4px;\n  color: rgba(212, 197, 160, 0.6);\n  font-family: inherit;\n  font-size: 11px;\n  cursor: pointer;\n  transition: all 0.2s;\n}\n\n.type-btn:hover {\n  border-color: rgba(139, 69, 19, 0.7);\n  color: rgba(212, 197, 160, 0.8);\n}\n\n.type-btn.active {\n  background: rgba(139, 69, 19, 0.3);\n  border-color: var(--rust);\n  color: rgba(212, 197, 160, 1);\n}\n\n/* 操作按钮 */\n.btn-action {\n  display: flex;\n  align-items: center;\n  gap: 6px;\n  padding: 8px 14px;\n  border: 1px solid;\n  border-radius: 4px;\n  font-family: inherit;\n  font-size: 11px;\n  font-weight: bold;\n  cursor: pointer;\n  transition: all 0.2s;\n}\n\n.btn-action:disabled {\n  opacity: 0.4;\n  cursor: not-allowed;\n}\n\n.btn-generate {\n  background: rgba(139, 69, 19, 0.3);\n  border-color: var(--rust);\n  color: rgba(255, 248, 220, 0.95);\n}\n\n.btn-generate:hover:not(:disabled) {\n  background: rgba(139, 69, 19, 0.5);\n}\n\n.btn-write {\n  background: rgba(74, 64, 53, 0.3);\n  border-color: rgba(139, 69, 19, 0.6);\n  color: rgba(212, 197, 160, 0.9);\n}\n\n.btn-write:hover:not(:disabled) {\n  background: rgba(74, 64, 53, 0.5);\n}\n\n.btn-clear {\n  background: transparent;\n  border-color: rgba(139, 69, 19, 0.3);\n  color: rgba(212, 197, 160, 0.5);\n}\n\n.btn-clear:hover {\n  background: rgba(139, 69, 19, 0.2);\n  border-color: rgba(139, 69, 19, 0.5);\n  color: rgba(212, 197, 160, 0.8);\n}\n\n.btn-retry {\n  background: rgba(180, 100, 30, 0.35);\n  border-color: rgba(180, 120, 40, 0.6);\n  color: rgba(230, 200, 140, 0.9);\n}\n\n.btn-retry:hover {\n  background: rgba(180, 100, 30, 0.55);\n  border-color: rgba(180, 120, 40, 0.9);\n  color: rgba(255, 248, 220, 1);\n}\n\n/* 状态栏 */\n.status-bar {\n  display: flex;\n  align-items: center;\n  gap: 8px;\n  padding: 6px 10px;\n  background: rgba(20, 18, 15, 0.8);\n  border-radius: 4px;\n  color: rgba(212, 197, 160, 0.7);\n  font-size: 11px;\n}\n\n.status-bar.success {\n  color: rgba(100, 200, 100, 0.9);\n}\n\n/* ========== 消息解析测试样式 ========== */\n\n.quick-tests {\n  display: flex;\n  flex-wrap: wrap;\n  align-items: center;\n  gap: 6px;\n  margin-bottom: 12px;\n  padding: 8px;\n  background: rgba(20, 18, 15, 0.5);\n  border-radius: 4px;\n}\n\n.quick-tests-label {\n  color: rgba(139, 69, 19, 0.9);\n  font-size: 10px;\n  text-transform: uppercase;\n  letter-spacing: 0.5px;\n}\n\n.quick-test-btn {\n  padding: 4px 10px;\n  background: rgba(139, 69, 19, 0.2);\n  border: 1px solid rgba(139, 69, 19, 0.4);\n  border-radius: 3px;\n  color: rgba(212, 197, 160, 0.7);\n  font-family: inherit;\n  font-size: 10px;\n  cursor: pointer;\n  transition: all 0.2s;\n}\n\n.quick-test-btn:hover {\n  background: rgba(139, 69, 19, 0.35);\n  border-color: rgba(139, 69, 19, 0.6);\n  color: rgba(212, 197, 160, 0.9);\n}\n\n.quick-test-btn:active {\n  background: rgba(139, 69, 19, 0.45);\n}\n\n/* 解析结果 */\n.parser-results {\n  margin-top: 12px;\n  border: 1px solid rgba(139, 69, 19, 0.3);\n  border-radius: 4px;\n  overflow: hidden;\n}\n\n.results-header {\n  display: flex;\n  align-items: center;\n  gap: 8px;\n  padding: 8px 10px;\n  background: rgba(42, 36, 32, 0.8);\n  color: rgba(212, 197, 160, 0.8);\n  font-size: 11px;\n  border-bottom: 1px solid rgba(139, 69, 19, 0.3);\n}\n\n.result-item {\n  padding: 10px;\n  border-bottom: 1px solid rgba(139, 69, 19, 0.2);\n  background: rgba(20, 18, 15, 0.6);\n}\n\n.result-item:last-child {\n  border-bottom: none;\n}\n\n.result-item.result-error {\n  background: rgba(139, 69, 19, 0.15);\n}\n\n.result-header {\n  display: flex;\n  align-items: center;\n  gap: 8px;\n  margin-bottom: 6px;\n}\n\n.result-index {\n  display: inline-flex;\n  align-items: center;\n  justify-content: center;\n  width: 20px;\n  height: 20px;\n  background: rgba(139, 69, 19, 0.3);\n  border-radius: 50%;\n  color: rgba(212, 197, 160, 0.8);\n  font-size: 9px;\n  font-weight: bold;\n}\n\n.result-type {\n  padding: 2px 8px;\n  background: rgba(139, 69, 19, 0.4);\n  border-radius: 3px;\n  color: rgba(212, 197, 160, 0.9);\n  font-size: 10px;\n  font-weight: bold;\n  text-transform: uppercase;\n}\n\n.result-character {\n  padding: 2px 8px;\n  background: rgba(74, 64, 53, 0.4);\n  border-radius: 3px;\n  color: rgba(212, 197, 160, 0.85);\n  font-size: 10px;\n}\n\n.result-text,\n.result-field {\n  margin-top: 4px;\n  color: rgba(212, 197, 160, 0.85);\n  font-size: 12px;\n  line-height: 1.4;\n}\n\n.result-field-label {\n  color: rgba(139, 69, 19, 0.9);\n  font-size: 10px;\n  text-transform: uppercase;\n}\n\n.result-error-text {\n  display: flex;\n  align-items: center;\n  gap: 6px;\n  margin-top: 6px;\n  padding: 6px 8px;\n  background: rgba(139, 69, 19, 0.2);\n  border-radius: 3px;\n  color: rgba(212, 197, 160, 0.7);\n  font-size: 11px;\n}\n\n.result-error-text i {\n  color: rgba(139, 69, 19, 0.9);\n}\n\n/* 裸文本结果 */\n.plain-text-result {\n  margin-top: 12px;\n  border: 1px solid rgba(139, 69, 19, 0.3);\n  border-radius: 4px;\n  overflow: hidden;\n}\n\n.plain-text-content {\n  margin: 0;\n  padding: 10px;\n  background: rgba(20, 18, 15, 0.6);\n  color: rgba(212, 197, 160, 0.85);\n  font-size: 12px;\n  line-height: 1.5;\n  white-space: pre-wrap;\n  word-break: break-all;\n}\n</style>\n"],"sourceRoot":""}]);
